export default async function GroupLayout({
  children,
  params,
}: {
  children: React.ReactNode
  params: Promise<{ id: string }>
}) {
  const { id } = await params  // 미래 탭 네비에서 사용
  return <div>{children}</div>
}

// app/protected/groups/[id]/page.tsx
async function GroupPage({ params }: { params: Promise<{ id: string }> }) {
  const { id } = await params
  supabase = await createClient()
  { data: authData, error } = await supabase.auth.getUser()
  if (error || !authData?.user) redirect('/auth/login')
  return <div><h1>그룹 홈</h1><p>준비 중</p></div>
}

